static uint32_t rotate(uint32_t x,unsigned n) { return (x>>n)|(x<<(32-n)); }
static uint32_t be32(const uint8_t *p) { return ((uint32_t)p[0]<<24)|((uint32_t)p[1]<<16)|((uint32_t)p[2]<<8)|p[3]; }
static void transform(struct sha256_context *c,const uint8_t *p) {
  uint32_t w[64],a=c->h[0],b=c->h[1],d=c->h[3],e=c->h[4],f=c->h[5],g=c->h[6],h=c->h[7],cc=c->h[2];
  for(unsigned i=0;i<16;i++) w[i]=be32(p+4*i);
  for(unsigned i=16;i<64;i++) { uint32_t x=w[i-15],y=w[i-2]; w[i]=(rotate(x,7)^rotate(x,18)^(x>>3))+w[i-16]+(rotate(y,17)^rotate(y,19)^(y>>10))+w[i-7]; }
  for(unsigned i=0;i<64;i++) { uint32_t t1=h+(rotate(e,6)^rotate(e,11)^rotate(e,25))+((e&f)^((~e)&g))+constants[i]+w[i]; uint32_t t2=(rotate(a,2)^rotate(a,13)^rotate(a,22))+((a&b)^(a&cc)^(b&cc)); h=g;g=f;f=e;e=d+t1;d=cc;cc=b;b=a;a=t1+t2; }
  c->h[0]+=a;c->h[1]+=b;c->h[2]+=cc;c->h[3]+=d;c->h[4]+=e;c->h[5]+=f;c->h[6]+=g;c->h[7]+=h;
}
static void init(struct sha256_context *c) { *c=(struct sha256_context){{0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19},0,{0},0}; }
static void update(struct sha256_context *c,const uint8_t *p,uint64_t n) { c->bytes+=n; while(n){ uint32_t take=64-c->used; if(take>n)take=(uint32_t)n; for(uint32_t i=0;i<take;i++)c->block[c->used+i]=p[i]; c->used+=take;p+=take;n-=take;if(c->used==64){transform(c,c->block);c->used=0;}} }
static void finish(struct sha256_context *c,uint8_t out[32]) { uint64_t bits=c->bytes*8;c->block[c->used++]=0x80;if(c->used>56){while(c->used<64)c->block[c->used++]=0;transform(c,c->block);c->used=0;}while(c->used<56)c->block[c->used++]=0;for(int i=7;i>=0;i--)c->block[c->used++]=(uint8_t)(bits>>(i*8));transform(c,c->block);for(unsigned i=0;i<8;i++){out[4*i]=c->h[i]>>24;out[4*i+1]=c->h[i]>>16;out[4*i+2]=c->h[i]>>8;out[4*i+3]=c->h[i];}}
void aiueos_sha256(const uint8_t *data,uint64_t length,uint8_t out[32]) { struct sha256_context c;init(&c);update(&c,data,length);finish(&c,out); }
